  "decrypto": {
    "categoryId": "word-games",
    "difficulty": "complicated",
    "content": {
      "en": {
        "metaDescription": "Expert Decrypto strategy: code entropy, interceptor baiting, and black-cell misdirection in 4-letter clue chains.",
        "intro": "Decrypto at the highest level is signaling through noise. White-hat teams optimize clue independence; black-hat play reads opponent entropy to intercept before the third round.",
        "quickTips": [
          "Clue words must be orthogonal—no shared roots across your three clues per round.",
          "Never reuse a clue concept that opponents saw you use in round 1.",
          "Interceptor teams log your clue-to-position mapping after first intercept.",
          "Misdirect with clue 3: make it look like a repeat pattern while clue 1-2 stay clean."
        ],
        "strategy": [
          "Entropy independence: each clue should partition the keyword space without overlapping semantic fields. If keywords share a domain, use number/texture/color axes instead of topic.",
          "Interceptor timing: intercept on round 2 when you have 2 data points per team—round 3 intercept is often too late with only one guess left.",
          "Black cell exploitation: when you must clue the black position, choose a word that could plausibly map to two different opponent keywords—forces wrong guesses.",
          "Opponent modeling: track which teammate gives the loosest clues; opponents will target that player's patterns first.",
          "Endgame lock: at 1 misdecode from loss, switch to ultra-literal clues even if intercept risk rises—one black is better than two."
        ]
      },
      "tr": {
        "metaDescription": "Uzman Decrypto stratejisi: kod entropisi, yakalama tuzağı ve siyah hucre yaniltma.",
        "intro": "Decrypto ust seviyede gurultu icinde sinyallesmedir. Beyaz takim bagimsiz ipucu optimize eder; siyah takim rakip entropisini okur.",
        "quickTips": [
          "Ipuclari ortogonal olmali; ortak kok kullanmayin.",
          "Rakibin gordugu ipucu kavramini tekrarlamayin.",
          "Yakalayicilar ilk interceptten sonra esleme loglar.",
          "3. ipucu ile yaniltin; 1-2 temiz kalsin."
        ],
        "strategy": [
          "Entropi bagimsizligi: anahtar kelime uzayini ortak alan olmadan bolun.",
          "Yakalama zamani: 2. turda 2 veri noktasi varken yakalayin.",
          "Siyah hucre: iki farkli rakip anahtar kelimeye uyabilecek kelime secin.",
          "Rakip modelleme: en gevsek ipucu veren oyuncuyu takip edin.",
          "Son oyun: bir hata kalinca ultra-literal ipuclara gecin."
        ]
      },
      "de": {
        "metaDescription": "Decrypto-Expertenstrategie: Code-Entropie, Interceptor-Koederung und Black-Cell-Misdirection.",
        "intro": "Decrypto auf Top-Niveau ist Signaling durch Rauschen. Weiss optimiert Unabhaengigkeit; Schwarz liest Gegner-Entropie.",
        "quickTips": [
          "Hinweise orthogonal—keine gemeinsamen Wurzeln.",
          "Gegnerische Konzepte nicht wiederholen.",
          "Interceptors loggen Mapping nach erstem Treffer.",
          "Hinweis 3 als Misdirection nutzen."
        ],
        "strategy": [
          "Entropie-Unabhaengigkeit: Keyword-Raum ohne Ueberlappung partitionieren.",
          "Interceptor-Timing: Runde 2 mit 2 Datenpunkten intercepten.",
          "Black Cell: Wort waehlen, das zu zwei Gegner-Keywords passt.",
          "Gegner-Modellierung: losesten Hinweisgeber tracken.",
          "Endgame-Lock: bei 1 Fehler ultra-literal werden."
        ]
      }
    }
  },
  "bananagrams": {
    "categoryId": "word-games",
    "difficulty": "simple",
    "content": {
      "en": {
        "metaDescription": "Expert Bananagrams: peel timing, grid topology for future splits, and dump-letter sequencing under race pressure.",
        "intro": "Bananagrams champions optimize grid shape for peel efficiency, not just raw anagram speed. Your cross-word layout determines how fast you absorb new tiles.",
        "quickTips": [
          "Build long horizontal spines with vertical branches—easier to peel into than square grids.",
          "Dump Q, Z, X, J into short words immediately; they bottleneck peels.",
          "Peel only when your grid has 2+ insertion points for any letter.",
          "Call 'Bananas' only when every branch can accept a wildcard letter."
        ],
        "strategy": [
          "Topology first: a T-shaped grid with 3 open ends beats a compact 4x4 that traps vowels in corners.",
          "Peel discipline: premature peels flood you with tiles while insertion points are locked—wait for 2+ open hooks.",
          "Letter dump sequencing: play V, K, W into 2-letter words attached to main spine before building fancy long words.",
          "Split recovery: when stuck, break a non-critical word to free a central vowel—speed beats aesthetics.",
          "Race psychology: opponents peel when you peel; slow-play to build hooks, then burst 3 peels in sequence to force their dump."
        ]
      },
      "tr": {
        "metaDescription": "Uzman Bananagrams: soyma zamani, grid topolojisi ve harf bosaltma sirasi.",
        "intro": "Bananagrams sampiyonlari anagram hizindan cok soyma verimliligi icin grid seklini optimize eder.",
        "quickTips": [
          "Uzun yatay omurga ve dikey dallar kare gridlerden iyidir.",
          "Q, Z, X, J'yi hemen kisa kelimelere gomun.",
          "2+ ekleme noktasi varken soyun.",
          "Her dal joker harf kabul edince Bananas deyin."
        ],
        "strategy": [
          "Topoloji oncelikli: 3 acik ucu olan T-grid, koseye hapsolmus seslilerden ustundur.",
          "Soyma disiplini: erken soyma kilitli noktalarda tas bogar.",
          "Harf bosaltma: V, K, W'yi once 2 harfli kelimelere.",
          "Bolme kurtarma: kritik olmayan kelimeyi kirarak sesli acin.",
          "Yaris psikolojisi: kancalari kur, sonra 3 soyma patlamasi yap."
        ]
      },
      "de": {
        "metaDescription": "Bananagrams-Expertenstrategie: Peel-Timing, Grid-Topologie und Dump-Sequencing.",
        "intro": "Bananagrams-Champions optimieren Grid-Form fuer Peel-Effizienz, nicht nur Anagramm-Speed.",
        "quickTips": [
          "Lange horizontale Spines mit vertikalen Aesten.",
          "Q, Z, X, J sofort in Kurzwoerter.",
          "Erst peelen bei 2+ Einfuegepunkten.",
          "Bananas nur bei offenen Hooks rufen."
        ],
        "strategy": [
          "Topologie zuerst: T-Grid mit 3 offenen Enden schlaegt kompaktes 4x4.",
          "Peel-Disziplin: fruehes Peelen ueberflutet bei gesperrten Hooks.",
          "Dump-Sequencing: V, K, W in 2-Buchstaben-Woerter.",
          "Split Recovery: unkritisches Wort brechen fuer Vokal.",
          "Race Psychology: Hooks bauen, dann 3-Peel-Burst."
        ]
      }
    }
  },
